@js:
let url = baseUrl;
let m = url.match(/tingshu\/(\d+)\/(\d+)\.html/);
if(!m) return '';
let html = java.ajax('https://www.qdysw.com/player.html?nid=' + m[1] + '&cid=' + m[2] + '&site=16');
let u = html.match(/url\d+\s*=\s*'(https?:\/\/[^']+)'/);
let ext = html.match(/murl\d+\s*=\s*'([^']+)'/);
if(u && ext) return u[1] + ext[1];
return '';
